+    /**
+     * Place a window at the requested cell even if it overlaps existing
+     * occupants. Existing cell markers are overwritten (the previous
+     * occupants remain in _windows but their cell tracking is lost for
+     * the overlapping cells — they'll be resolved on next placement
+     * operation). Used as a last-resort fallback when the grid is full.
+     */
+    forcePlaceWindow(windowId, col, row, spanCols, spanRows) {
+        const clampedCols = Math.min(spanCols, this.cols);
+        const clampedRows = Math.min(spanRows, this.rows);
+        const clampedCol = Math.max(0, Math.min(col, this.cols - clampedCols));
+        const clampedRow = Math.max(0, Math.min(row, this.rows - clampedRows));
+        this._markCells(clampedCol, clampedRow, clampedCols, clampedRows, windowId);
+        this._windows.set(windowId, {
+            col: clampedCol, row: clampedRow,
+            spanCols: clampedCols, spanRows: clampedRows,
+        });
+        return {col: clampedCol, row: clampedRow};
+    }
+
